  1	import * as React from 'react';
  2	import {
  3	  Alert,
  4	  AlertGroup,
  5	  AlertActionCloseButton,
  6	  AlertActionLink,
  7	} from '@patternfly/react-core';
  8	import { ToastOptions, ToastContext, ToastContextType } from './ToastContext';
  9	
 10	export const ToastProvider: React.FC = ({ children }) => {
 11	  const [toasts, setToasts] = React.useState<ToastOptions[]>([]);
 12	
 13	  const removeToast = React.useCallback((id: string) => {
 14	    setToasts((state) => {
 15	      const index = state.findIndex((t) => t.id === id);
 16	      if (index !== -1) {
 17	        const toast = state[index];
 18	        if (toast.onRemove) {
 19	          toast.onRemove(toast.id);
 20	        }
 21	        return [
 22	          ...state.slice(0, index),
 23	          ...state.slice(index + 1, state.length),
 24	        ];
 25	      }
 26	      return state;
 27	    });
 28	  }, []);
 29	
 30	  const addToast = React.useMemo(() => {
 31	    let counter = 0;
 32	    return (toast: ToastOptions) => {
 33	      const clone: ToastOptions = {
 34	        id: `toast-${++counter}`,
 35	        ...toast,
 36	      };
 37	      setToasts((state) => {
 38	        const index = state.findIndex((t) => t.id === clone.id);
 39	        if (index !== -1) {
 40	          return [
 41	            ...state.slice(0, index),
 42	            clone,
 43	            ...state.slice(index + 1, state.length),
 44	          ];
 45	        }
 46	        return [...state, clone];
 47	      });
 48	      return clone.id;
 49	    };
 50	  }, []);
 51	
 52	  const controller: ToastContextType = React.useMemo<ToastContextType>(
 53	    () => ({
 54	      addToast,
 55	      removeToast,
 56	    }),
 57	    [addToast, removeToast],
 58	  );
 59	
 60	  return (
 61	    <ToastContext.Provider value={controller}>
 62	      {children}
 63	      {toasts.length ? (
 64	        <AlertGroup appendTo={() => document.body} isToast>
 65	          {toasts.map((toast) => (
 66	            <Alert
 67	              key={toast.id}
 68	              isLiveRegion
 69	              title={toast.title}
 70	              variant={toast.variant}
 71	              timeout={toast.timeout}
 72	              onTimeout={() => removeToast(toast.id)}
 73	              data-test={`${toast.title} alert`}
 74	              actionClose={
 75	                toast.dismissible ? (
 76	                  <AlertActionCloseButton
 77	                    onClose={() => {
 78	                      toast.onClose && toast.onClose();
 79	                      removeToast(toast.id);
 80	                    }}
 81	                  />
 82	                ) : undefined
 83	              }
 84	              actionLinks={
 85	                toast.actions?.length > 0 ? (
 86	                  <>
 87	                    {toast.actions.map((action) => (
 88	                      <AlertActionLink
 89	                        key={action.label}
 90	                        onClick={() => {
 91	                          if (action.dismiss) {
 92	                            removeToast(toast.id);
 93	                          }
 94	                          action.callback();
 95	                        }}
 96	                        component={action.component}
 97	                        data-test={action.dataTest || 'toast-action'}
 98	                      >
 99	                        {action.label}
100	                      </AlertActionLink>
101	                    ))}
102	                  </>
103	                ) : undefined
104	              }
105	            >
106	              {toast.content}
107	            </Alert>
108	          ))}
109	        </AlertGroup>
110	      ) : null}
111	    </ToastContext.Provider>
112	  );
113	};

